var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JUDGE_CHARADE_NPC_NULL","text":{"KOREA":"이상, 중요 참고인들의 증언을 바탕으로…….","JPN":"以上、重要参考人の証言をもとに……","ENG":"In the light of the testimony provided by material witnesses...","TWN":"以上，根據幾位重要證人的證詞……"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JUDGE_CHARADE_NPC_NULL","text":{"KOREA":"피고의 간첩 행위 및 관리국의 핵심 기밀을 유출한 혐의가 사실로 밝혀졌습니다.","JPN":"被告のスパイ行為および管理局の核心的機密を漏洩させた疑いが事実であることが明らかになりました。","ENG":"It is evident that the defendant took part in espionage and leaked key secrets of the Administration.","TWN":"認定被告涉嫌從事間諜活動及洩漏管理局重要機密的罪證屬實，"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JUDGE_CHARADE_NPC_NULL","text":{"KOREA":"허나 피고는 여전히 잘못을 뉘우치지 않고, 범행을 부인하는 모습을 보이고 있습니다.","JPN":"ですが、被告はいまだに反省せず、犯行を否認する姿勢を見せています。","ENG":"However, she denies any involvement in the alleged offense and shows no remorse.","TWN":"然而，被告犯後毫無悔意，並且否認犯行，"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JUDGE_CHARADE_NPC_NULL","text":{"KOREA":"이에 따라, 본 재판부는 피고에게 종신형을 선고하는 바입니다.","JPN":"よって、本法廷は被告に終身刑を言い渡します。","ENG":"Accordingly, the court sentences the defendant to life imprisonment.","TWN":"因此，當庭宣判處以被告無期徒刑。"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"남자한테 눈이 멀어서 핵심 기밀을 팔아 넘기다니…. 믿기지가 않아.","JPN":"男にハマって核心的機密を売り飛ばすとは……信じられない。","ENG":"I can't believe it... She sold the Administration's secrets all for a man she barely knows.","TWN":"被男人迷得團團轉洩漏出重要機密…真不敢相信。"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니까요. 남편이랑 애만 딱하게 됐네요.","JPN":"本当です。旦那さんとお子さんがかわいそうですよね。","ENG":"I know. I feel sorry for her husband and daughter.","TWN":"就是說啊，把老公和孩子害得這麼悽慘。"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"불쌍할 게 뭐 있어? 남편도 한통속일지 누가 알아.","JPN":"何もかわいそうだなんて思う必要ないだろう？　旦那も一緒にやったのかもしれないし。","ENG":"Why do you feel sorry for them? Who knows? Maybe the husband was in on it too.","TWN":"有什麼好慘的？說不定她老公和她是一夥的，誰知道？"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"빼앗긴 아티팩트는 이제 무슨 수로 되찾아 올 건데?","JPN":"奪われたアーティファクトはどうやって取り戻すんだ？","ENG":"So how are they going to get back the stolen Artifact?","TWN":"現在要怎麼把被搶走的人造神器找回來？"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"사라졌다는 <color=#ffd34c>콜드 케이스</color>라는 게…… 그렇게 중요한 물건인가요?","JPN":"消えた<color=#ffd34c>コールドケース</color>って……そんなに大事な物なんですか？","ENG":"The missing <color=#ffd34c>Cold Case</color>... Is it that important?","TWN":"那個不見的<color=#ffd34c>Cold Case</color>……是很重要的東西嗎？"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"……쉿. 멍청아. 기밀 사항이라고. 목소리 낮춰.","JPN":"……しっ。バカ。機密事項なんだ。声を抑えろ。","ENG":"...Shush, you idiot. Keep your voice down! It's top secret.","TWN":"……噓！你這笨蛋，這可是機密，小聲一點！"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"믿고 있었는데…….","JPN":"信じてたのに……","ENG":"I trusted you...","TWN":"我那麼相信你……"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"솔직하게 말하면, 엄마랑 아빠가 감옥에 가지 않게 도와줄 거라고 했으면서!","JPN":"正直に話したら、ママとパパが刑務所に行かないようにしてくれるって言ったのに！","ENG":"You said that if I told the truth, that you would help Mommy and Daddy not go to jail!","TWN":"是你說不會讓爸爸媽媽進去坐牢的！"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"이럴 줄 알았으면…… 아무것도 말하지 말 걸…….","JPN":"こうなるとわかってたら……何も言わなかった……","ENG":"If I knew this was going to happen... I would've kept my mouth shut...","TWN":"早知道會這樣……我一句話都不會說……"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"나 때문에, 나 때문에 엄마, 아빠가…….","JPN":"私のせいで、私のせいでママとパパが……","ENG":"It's all because of me... that Mommy and Daddy are...","TWN":"都是我害的，都是我，害爸爸媽媽……"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"무슨 착각을 하는 거니, 루이즈?","JPN":"何を勘違いしてるのかしら？　ルイーズ。","ENG":"What are you talking about, Louisé?","TWN":"你是不是哪裡有誤會，露易絲？"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"네가 본 걸 숨겨 봤자, 너희 부모님이 저지른 죄가 없던 걸로 되는 건 아니잖아.","JPN":"あなたが見たことを隠しても、あなたの両親の犯した罪がなかったことにはならないわ。","ENG":"Even if you hide the truth, it doesn't make the crimes your parents committed go away.","TWN":"就算你不說你看到什麼，也不表示你父母就是無罪的。"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"나도 안타깝지만, 죄 지은 사람은 그에 합당한 벌을 받아야지.","JPN":"私も残念だと思うけど、罪を犯した人はそれ相応の罰を受けないとね。","ENG":"It's a shame, but bad people must be punished for what they did.","TWN":"我也覺得很遺憾，但犯罪的人就該受到應有的懲罰。"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHARADE_001","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};